// DELETE /upload/:type/:filename - Delete an uploaded file
app.delete('/upload/:type/:filename', (req, res) => {
  try {
    const { type, filename } = req.params;

    // Sanitize filename to prevent directory traversal
    const sanitizedFilename = path.basename(filename);

    let dirPath;
    if (type === 'avatar') {
      dirPath = avatarDir;
    } else if (type === 'document') {
      dirPath = documentDir;
    } else {
      return res.status(400).json({
        success: false,
        error: 'Invalid type',
        message: 'Type must be "avatar" or "document".'
      });
    }

    const filePath = path.join(dirPath, sanitizedFilename);

    if (!fs.existsSync(filePath)) {
      return res.status(404).json({
        success: false,
        error: 'File not found',
        message: 'The specified file does not exist.'
      });
    }

    // Delete the main file
    fs.unlinkSync(filePath);

    // Try to delete associated thumbnail
    const thumbPatterns = [
      `thumb-${sanitizedFilename}`,
      `thumb-${path.parse(sanitizedFilename).name}.png`
    ];

    for (const thumbName of thumbPatterns) {
      const thumbPath = path.join(thumbnailDir, thumbName);
      if (fs.existsSync(thumbPath)) {
        fs.unlinkSync(thumbPath);
      }
    }

    res.status(200).json({
      success: true,
      message: 'File deleted successfully'
    });
  } catch (error) {
    console.error('File deletion error:', error);
    res.status(500).json({
      success: false,
      error: 'Server error',
      message: 'An error occurred while deleting the file.'
    });
  }
});

